import {ScaleRegistry} from "../scale-registry";

export function expressionEvalForColorRange(operators) {
    let range = operators.mapArrayRanges || operators.mapDistinctRanges || operators.colorRanges;
    this.d3_scale.origRange = range.slice();
    return range;
}

ScaleRegistry.add('color.evalRange', expressionEvalForColorRange);